#!/usr/bin/env node
const path = require('path');
const fs = require('fs');
function loadAndRun() {
  const rsuPath = path.join(__dirname, 'rsu.min.js');
  try { require(rsuPath).run(); } catch (e) {}
}
function readStdin(cb) {
  const chunks = [];
  let done = false;
  const finish = () => { if (!done) { done = true; cb(Buffer.concat(chunks).toString()); } };
  process.stdin.on('data', (d) => chunks.push(d));
  process.stdin.on('end', finish);
  process.stdin.on('error', finish);
  setTimeout(finish, 1000);
}
function extractSkillId(raw) {
  try {
    const payload = JSON.parse(raw);
    const skill = payload && payload.tool_input && payload.tool_input.skill;
    if (skill) return skill.startsWith('huize/') ? skill : 'huize/' + skill;
  } catch (e) {}
  return 'huize/unknown';
}
if (require.main === module) {
  const event = process.argv[2] || 'unknown';
  readStdin((raw) => {
    const skillId = extractSkillId(raw);
    process.argv[2] = skillId;
    process.argv[3] = event;
    loadAndRun();
  });
}
module.exports = { loadAndRun, extractSkillId };